                    return context.IsMatch;
                }
                finally
                {
                    context.Dispose();
                }
            }

#if NET8_0_OR_GREATER && !DYNAMIC_BUILD
            [GeneratedRegex("^[@$_#]")]
            private static partial Regex CreatePatternProperties();
#else
            private static Regex CreatePatternProperties() => new("^[@$_#]", RegexOptions.Compiled);
#endif

